mapper.insert:
insert into seat_reservation

    seat_id
    user_id
    date
    start_time
    end_time

    values

        #{seatId}
        #{userId}
        #{date}
        #{startTime}
        #{endTime}

mapper.select:
select r.id, stu.name as userName, r.seat_id as seatId, s.seat_number as seatNumber,
       r.date, r.start_time as startTime, r.end_time as endTime, r.leave_time as leaveTime, r.status,
       s.room_id as roomId, CONCAT('阅览室', s.room_id) as areaName
from seat_reservation r
left join student stu on r.user_id = stu.id
left join seat s on r.seat_id = s.id

    and r.user_id = #{userId}
    and r.seat_id = #{seatId}
    and r.date = #{date}
    and r.status = #{status}
